
  CREATE TABLE "DIRKSPZM32"."ISI_RESOURCE" 
   (	"SID" VARCHAR2(2 CHAR) DEFAULT '01' NOT NULL ENABLE, 
	"RES_ID" NUMBER(*,0) NOT NULL ENABLE, 
	"FIRMA_NR" NUMBER(6,0) DEFAULT 1 NOT NULL ENABLE, 
	"TYP" VARCHAR2(5 CHAR) NOT NULL ENABLE, 
	"RES_NAME" VARCHAR2(25 CHAR) NOT NULL ENABLE, 
	"VARIANTE" NUMBER(*,5) NOT NULL ENABLE, 
	"GRUPPE" NUMBER(*,5), 
	"TEXT" VARCHAR2(100 CHAR), 
	"LAGER_ROH" VARCHAR2(30 CHAR), 
	"LAGER_FERTIG" VARCHAR2(30 CHAR), 
	"RES_EXT_NAME" VARCHAR2(25 CHAR), 
	"FEHLER_SCHLUESSEL" NUMBER(*,5), 
	"ORTS_KZ" VARCHAR2(50 CHAR), 
	"PARENT_RES_ID" NUMBER(*,0), 
	"POS_INFO" VARCHAR2(255 CHAR), 
	"PARENT_RES_START" DATE, 
	"LINIE_RES_ID" NUMBER(*,0), 
	"LOGIN_ID_VERANTW" NUMBER(*,0), 
	"ADRESS_ID" NUMBER(*,0), 
	"VISUNAME" VARCHAR2(15 CHAR), 
	"KATEGORIE" VARCHAR2(40 CHAR), 
	"KATEGORIE_TYP" VARCHAR2(15 CHAR), 
	"MAX_KG" NUMBER(*,6), 
	"COM_NAME" VARCHAR2(50 CHAR), 
	"POLLMSEK" NUMBER(*,12), 
	"DRUCKER" VARCHAR2(255 CHAR), 
	"RES_PARAMS_CFG" VARCHAR2(4000 CHAR), 
	"RES_KST" VARCHAR2(15 CHAR)
   ) ;
ALTER TABLE "DIRKSPZM32"."ISI_RESOURCE" ADD CONSTRAINT "CHECK_ISI_RESOURCE_TYP" CHECK (TYP in ('RFZ', 'RBG',  'LI', 'ST', 'MG', 'MHG', 'MS', 'MA', 'MAG', 'MG',  'MHG', 'MPG', 'MPP', 'IP', 'DR', 'KP', 'KPQ', 'KPZ', 'VPG', 'VP', 'ST', 'LI', 'WKZ', 'FHM', 'MSMP', 'ZET')) ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_RESOURCE" ADD CONSTRAINT "PK_RESOURCE" PRIMARY KEY ("RES_ID")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."ISI_RESOURCE" ADD CONSTRAINT "UK_RESOURCE" UNIQUE ("TYP", "RES_NAME")
  USING INDEX  ENABLE;


